using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// A simple extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class ExtractiveSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
        ["the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
         "have", "has", "had", "do", "does", "did", "will", "would", "could",
         "should", "may", "might", "shall", "can", "need", "dare", "ought",
         "used", "to", "of", "in", "for", "on", "with", "at", "by", "from",
         "as", "into", "through", "during", "before", "after", "above",
         "below", "between", "out", "off", "over", "under", "again",
         "further", "then", "once", "and", "but", "or", "nor", "not", "so",
         "yet", "both", "either", "neither", "each", "every", "all", "any",
         "few", "more", "most", "other", "some", "such", "no", "only",
         "own", "same", "than", "too", "very", "just", "because", "if",
         "when", "where", "how", "what", "which", "who", "whom", "this",
         "that", "these", "those", "i", "me", "my", "myself", "we", "our",
         "ours", "ourselves", "you", "your", "yours", "he", "him", "his",
         "she", "her", "hers", "it", "its", "they", "them", "their"];

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitSentences(documentText);
        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, i) => (Index: i, Sentence: s, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static string[] SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text.Trim())
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToArray();
    }

    private static Dictionary<string, int> BuildWordFrequencies(string[] sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (StopWords.Contains(word.ToLowerInvariant()) || word.Length < 2)
                    continue;

                var lower = word.ToLowerInvariant();
                freq[lower] = freq.GetValueOrDefault(lower) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = TokenizeWords(sentence);
        if (words.Length == 0) return 0;

        double score = 0;
        foreach (var word in words)
        {
            var lower = word.ToLowerInvariant();
            if (wordFrequencies.TryGetValue(lower, out int freq))
                score += freq;
        }
        return score / words.Length;
    }

    private static string[] TokenizeWords(string text) =>
        WordRegex().Matches(text).Select(m => m.Value).ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

